var reductionOperations = function(nums) {
    nums.sort((a, b) => a - b);
    let ops = 0, levels = 0;
    for (let i = 1; i < nums.length; i++) {
        if (nums[i] !== nums[i - 1]) levels += 1;
        ops += levels;
    }
    return ops;
};
